// ─────────────────────────────────────────────────────────────────────────────
// src/hooks/useAppState.js
// Central state hook — owns all mutable application state and exposes
// action functions so child components never mutate state directly.
// ─────────────────────────────────────────────────────────────────────────────

import { useState } from "react";
import {
  LEAVE_REQUESTS_DATA,
  HOLIDAYS_DATA,
  EMPLOYEES_DATA,
  LEAVE_BALANCES_DATA,
} from "../data/mockData";
import { daysBetween } from "../utils/helpers";

export function useAppState() {
  const [user,      setUser]      = useState(null);
  const [activeTab, setActiveTab] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const [leaves,    setLeaves]    = useState(LEAVE_REQUESTS_DATA);
  const [holidays,  setHolidays]  = useState(HOLIDAYS_DATA);
  const [employees]               = useState(EMPLOYEES_DATA);
  const [balances,  setBalances]  = useState(LEAVE_BALANCES_DATA);

  // ── Auth ────────────────────────────────────────────────────────────────────
  const login = (selectedUser) => {
    setUser(selectedUser);
    setActiveTab("dashboard");
  };

  const logout = () => {
    setUser(null);
    setActiveTab("dashboard");
  };

  // ── Leave actions ────────────────────────────────────────────────────────────
  /**
   * Submit a new leave application (sets status to "pending")
   */
  const submitLeave = (form) => {
    const days = daysBetween(form.startDate, form.endDate);
    const newLeave = {
      id:         leaves.length + 10,
      empId:      user.id,
      leaveType:  form.leaveType,
      startDate:  form.startDate,
      endDate:    form.endDate,
      days,
      reason:     form.reason,
      status:     "pending",
      appliedOn:  "2025-03-26",
      approvedBy: null,
      comments:   "",
    };
    setLeaves((prev) => [newLeave, ...prev]);
  };

  /**
   * Cancel a pending leave request (employee action)
   */
  const cancelLeave = (id) => {
    setLeaves((prev) =>
      prev.map((l) => (l.id === id ? { ...l, status: "cancelled" } : l))
    );
  };

  /**
   * Approve or reject a leave request (HR/Admin action)
   * Automatically deducts balance on approval.
   */
  const reviewLeave = (leaveId, action, comment, reviewerId) => {
    const leave = leaves.find((l) => l.id === leaveId);
    if (!leave) return;

    setLeaves((prev) =>
      prev.map((l) =>
        l.id === leaveId
          ? { ...l, status: action, approvedBy: reviewerId, comments: comment }
          : l
      )
    );

    if (action === "approved") {
      setBalances((prev) => {
        const empBal = { ...(prev[leave.empId] || {}) };
        empBal[leave.leaveType] = Math.max(
          0,
          (empBal[leave.leaveType] || 0) - leave.days
        );
        return { ...prev, [leave.empId]: empBal };
      });
    }
  };

  // ── Holiday actions ──────────────────────────────────────────────────────────
  const addHoliday = (holidayData) => {
    setHolidays((prev) => [
      ...prev,
      { id: prev.length + 10, ...holidayData },
    ]);
  };

  const deleteHoliday = (id) => {
    setHolidays((prev) => prev.filter((h) => h.id !== id));
  };

  // ── Derived values ───────────────────────────────────────────────────────────
  const pendingCount = leaves.filter((l) => l.status === "pending").length;

  return {
    // State
    user,
    activeTab,
    sidebarOpen,
    leaves,
    holidays,
    employees,
    balances,
    pendingCount,

    // Navigation
    setActiveTab,
    setSidebarOpen,

    // Auth
    login,
    logout,

    // Leave actions
    submitLeave,
    cancelLeave,
    reviewLeave,

    // Holiday actions
    addHoliday,
    deleteHoliday,
  };
}
